function paginateData(data, page, size = 20) {
    const start = (page - 1) * size;
    const end = start + size;
    return {
        content: data.slice(start, end),
        totalElements: data.length,
        totalPages: Math.ceil(data.length / size),
        currentPage: page
    };
}
